## How to reproduce?

As explained in the bug report above, create a custom server running HTTPS, and invoke a middleware function that will read the original request url:

```js
// server.js
const { createServer } = require('https')
const { readFileSync } = require('fs')
const next = require('next')
const { join } = require('path')
const port = 4000
const app = next({ dev: true, hostname: 'localhost', port })
const handle = app.getRequestHandler()
const httpsOptions = {
  // NODE_TLS_REJECT_UNAUTHORIZED=0 required since self-signed certificates
  key: readFileSync(join(__dirname, 'ssh/privkey.pem')),
  cert: readFileSync(join(__dirname, 'ssh/cert.pem')),
}

app.prepare().then(() => {
  const server = createServer(httpsOptions, handle)
  server.listen(port, (err) => {
    if (err) throw err
    console.log('> Server started on ', server.address())
  })
})

// middleware.js
import { NextResponse } from 'next/server'

export default function middleware(req) {
  const response = NextResponse.next()
  response.headers.append('x-original-url', req.url)
  return response
}
```

Then curl it (with -k to allow insecure https connection, since we're using self-signed certificates)
```
curl https://localhost:4000 -v -k
```


